// Handle both direct webhook and sub-workflow calls
const raw = $input.first().json;
const data = raw.body || raw;
const { ideaPrompt = '', briefId = '' } = data;

// Build YouTube search queries
const queries = [
  `${ideaPrompt.slice(0, 80)} tutorial`,
  `${ideaPrompt.slice(0, 80)} implementation guide`,
];

return queries.map(q => ({ json: { query: q, briefId } }));

// Process YouTube search results (HTML scraping — no API key needed)
const allSources = [];

for (const item of $input.all()) {
  const body = typeof item.json === 'string' ? item.json : (item.json?.body || item.json?.data || JSON.stringify(item.json));
  const html = typeof body === 'string' ? body : '';

  // Extract video IDs from YouTube HTML
  const videoIdMatches = html.match(/"videoId":"([a-zA-Z0-9_-]{11})"/g) || [];
  const titleMatches = html.match(/"title":\{"runs":\[\{"text":"([^"]+)"/g) || [];

  const videoIds = [...new Set(videoIdMatches.map(m => m.match(/"([a-zA-Z0-9_-]{11})"/)?.[1]).filter(Boolean))];

  for (let i = 0; i < Math.min(videoIds.length, 5); i++) {
    const videoId = videoIds[i];
    let title = `YouTube Video ${i + 1}`;
    if (titleMatches[i]) {
      const m = titleMatches[i].match(/"text":"([^"]+)"/);
      if (m) title = m[1];
    }

    allSources.push({
      sourceType: 'youtube',
      url: `https://www.youtube.com/watch?v=${videoId}`,
      title: title.slice(0, 500),
      snippet: `YouTube video about: ${title}`.slice(0, 300),
      trustScore: 55,
      rawPayload: {
        source: 'n8n',
        workflowType: 'youtube_research',
        videoId
      }
    });
  }
}

// Deduplicate
const seen = new Set();
const unique = allSources.filter(s => {
  if (seen.has(s.url)) return false;
  seen.add(s.url);
  return true;
}).slice(0, 5);

return [{ json: {
  sources: unique,
  metadata: {
    workflowName: 'nexus-youtube-research',
    totalVideos: unique.length
  }
}}];
